#!/usr/bin/env bash
set -euo pipefail
ROOT="${1:-$PWD}"
if [[ ! -f "$ROOT/pyproject.toml" || ! -d "$ROOT/src/grid_world" ]]; then
  echo "ERROR: $ROOT is not a grid-world repository." >&2
  exit 1
fi
TMP="$(mktemp -d)"
base64 -d > "$TMP/patch.zip" <<'GRID_WORLD_ALL_LAYERS_NO_GRID'

GRID_WORLD_ALL_LAYERS_NO_GRID
unzip -qo "$TMP/patch.zip" -d "$ROOT"
rm -rf "$TMP"
chmod +x "$ROOT"/scripts/prepare_analysis_view.py "$ROOT"/scripts/plot_layer_curves.py "$ROOT"/scripts/compare_layer_conditions.py "$ROOT"/scripts/run_explicit_all_layers.sh "$ROOT"/scripts/run_no_grid_full.sh
cd "$ROOT"
python -m compileall -q src scripts
bash -n scripts/run_explicit_all_layers.sh
bash -n scripts/run_no_grid_full.sh
PYTHONPATH="$ROOT/src${PYTHONPATH:+:$PYTHONPATH}" python -m pytest -q tests/test_parser_modes.py tests/test_no_grid.py tests/test_layer_curves.py tests/test_grid.py tests/test_parser.py tests/test_targets.py
echo "All-layer and no-grid upgrade installed successfully."
echo "Explicit all layers: bash scripts/run_explicit_all_layers.sh"
echo "No-grid full run: bash scripts/run_no_grid_full.sh"
